Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh via RefreshView wrapper -->
        <CollectionView.Behaviors>
            <!-- OR wrap in RefreshView (see below) -->
        </CollectionView.Behaviors>

        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</ContentPage>
```

Since `CollectionView` doesn't have built-in pull-to-refresh, wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    // Fires automatically when SelectedItem changes (MVVM Toolkit convention)
    partial void OnSelectedItemChanged(Item? value)
    {
        if (value is null) return;

        // Navigate, then clear selection so the same item can be re-selected
        _nav.NavigateAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = value
        });

        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `ItemsSource → Items` | Drives the list from an `ObservableCollection` |
| `SelectedItem → SelectedItem` | Two-way; triggers `OnSelectedItemChanged` for navigation |
| `RefreshView.Command → RefreshCommand` | Auto-generated by `[RelayCommand]` on `RefreshAsync` |
| `IsRefreshing → IsRefreshing` | Two-way; set `false` when done to dismiss the spinner |

**Important details:**
- Set `SelectedItem = null` after navigating so the user can tap the same item again.
- Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on errors.
- Uses **CommunityToolkit.Mvvm** (`ObservableObject`, `[ObservableProperty]`, `[RelayCommand]`) to eliminate boilerplate.
